import{c as i,a7 as a,y as n,B as t}from"./chunks/framework.3cjvm90C.js";const k=JSON.parse('{"title":"TF-IDF","description":"TF-IDF 文本特征提取方法的原理与实现","frontmatter":{"title":"TF-IDF","description":"TF-IDF 文本特征提取方法的原理与实现"},"headers":[],"relativePath":"dlwiki/nlp/tfidf.md","filePath":"dlwiki/nlp/tfidf.md","lastUpdated":1782456021000}'),p={name:"dlwiki/nlp/tfidf.md"};function e(l,s,r,h,o,c){return a(),n("div",null,[...s[0]||(s[0]=[t(`<h2 id="tf-idf" tabindex="-1">TF-IDF <a class="header-anchor" href="#tf-idf" aria-label="Permalink to “TF-IDF”">​</a></h2><p>TF-IDF(term frequency–inverse document frequency)是一种用于信息检索与数据挖掘的常用加权技术，常用于挖掘文章中的关键词，而且算法简单高效，常被工业用于最开始的文本数据清洗。</p><p>TF-IDF 有两层意思，一层是&quot;词频&quot;（Term Frequency，缩写为 TF），另一层是&quot;逆文档频率&quot;（Inverse Document Frequency，缩写为 IDF）。</p><p>假设我们现在有一片长文叫做《量化系统架构设计》词频高在文章中往往是停用词，“的”，“是”，“了”等，这些在文档中最常见但对结果毫无帮助、需要过滤掉的词，用 TF 可以统计到这些停用词并把它们过滤。当高频词过滤后就只需考虑剩下的有实际意义的词。</p><p>但这样又会遇到了另一个问题，我们可能发现&quot;量化&quot;、&quot;系统&quot;、&quot;架构&quot;这三个词的出现次数一样多。这是不是意味着，作为关键词，它们的重要性是一样的？事实上系统应该在其他文章比较常见，所以在关键词排序上，“量化”和“架构”应该排在“系统”前面，这个时候就需要 IDF，IDF 会给常见的词较小的权重，它的大小与一个词的常见程度成反比。</p><p><strong>当有 TF(词频)和 IDF(逆文档频率)后，将这两个词相乘，就能得到一个词的 TF-IDF 的值。某个词在文章中的 TF-IDF 越大，那么一般而言这个词在这篇文章的重要性会越高，所以通过计算文章中各个词的 TF-IDF，由大到小排序，排在最前面的几个词，就是该文章的关键词。</strong></p><p><img src="https://pic3.zhimg.com/80/v2-e3748e7dd4056e0a98d7c9892d11cc52_1440w.jpg" alt="img"></p><h3 id="tf-idf-算法步骤" tabindex="-1"><strong>TF-IDF 算法步骤</strong> <a class="header-anchor" href="#tf-idf-算法步骤" aria-label="Permalink to “TF-IDF 算法步骤”">​</a></h3><p>第一步，计算词频：</p><p><img src="https://pic4.zhimg.com/80/v2-281a550de928afe343c055d06371cf77_1440w.jpg" alt="img"></p><p>考虑到文章有长短之分，为了便于不同文章的比较，进行&quot;词频&quot;标准化。</p><p><img src="https://pic2.zhimg.com/80/v2-393435b342546a2f1736d1d755adb1cd_1440w.jpg" alt="img"></p><p>第二步，计算逆文档频率：</p><p>这时，需要一个语料库（corpus），用来模拟语言的使用环境。</p><p><img src="https://pic2.zhimg.com/80/v2-1d5c436e04f497544d72fec6909a3fad_1440w.jpg" alt="img"></p><p>如果一个词越常见，那么分母就越大，逆文档频率就越小越接近 0。分母之所以要加 1，是为了避免分母为 0（即所有文档都不包含该词）。log 表示对得到的值取对数。</p><p>第三步，计算 TF-IDF：</p><p><img src="https://pic3.zhimg.com/80/v2-5560a4b2efa3330021b8b2ef13a471fe_1440w.jpg" alt="img"></p><p>可以看到，TF-IDF 与一个词在文档中的出现次数成正比，与该词在整个语言中的出现次数成反比。所以，自动提取关键词的算法就很清楚了，就是<strong>计算出文档的每个词的 TF-IDF 值，然后按降序排列，取排在最前面的几个词。</strong></p><h3 id="优缺点" tabindex="-1"><strong>优缺点</strong> <a class="header-anchor" href="#优缺点" aria-label="Permalink to “优缺点”">​</a></h3><p>BOW 模型有很多缺点，首先它没有考虑单词之间的顺序，其次它无法反应出一个句子的关键词，比如下面这个句子：</p><p>&quot;John likes to play football, Mary likes too&quot;</p><p>这个句子若用 BOW 模型，它的词表为：[‘football’, ‘john’, ‘likes’, ‘mary’, ‘play’, ‘to’, ‘too’]，则词向量表示为：[1 1 2 1 1 1 1]。若根据 BOW 模型提取这个句子的关键词，则为 “like”，但是显然这个句子的关键词应该为 “football”。而 TF-IDF 则可以解决这个问题。</p><div class="language-python line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">from</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> sklearn.feature_extraction.text </span><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">import</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> TfidfVectorizer</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">corpus = [</span></span>
<span class="line"><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">    &#39;This is the first document.&#39;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">,</span></span>
<span class="line"><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">    &#39;This document is the second document.&#39;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">,</span></span>
<span class="line"><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">    &#39;And this is the third one.&#39;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">,</span></span>
<span class="line"><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">    &#39;Is this the first document?&#39;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">,</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">vectorizer = TfidfVectorizer()</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">X = vectorizer.fit_transform(corpus)</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">print</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">(vectorizer.get_feature_names())</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">print</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">(X)</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">print</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">(X.toarray())</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>TF-IDF 的优点是简单快速，而且容易理解。缺点是有时候用<strong>词频</strong>来衡量文章中的一个词的重要性不够全面，有时候重要的词出现的可能不够多，而且这种计算无法体现位置信息，无法体现词在上下文的重要性。如果要体现词的上下文结构，那么你可能需要使用 word2vec 算法来支持。</p>`,25)])])}const D=i(p,[["render",e]]);export{k as __pageData,D as default};
